# frozen_string_literal: true

# ================================================================
# Tests for WebComponentRenderer
# ================================================================
#
# The Web Components renderer emits TypeScript Custom Element classes.
# We run end-to-end (source → analyze → VM → renderer → TS)
# and check the generated file content.
# ================================================================

require "minitest/autorun"
require "coding_adventures_mosaic_analyzer"
require "coding_adventures_mosaic_vm"
require "coding_adventures_mosaic_emit_webcomponent"

class TestMosaicEmitWebcomponent < Minitest::Test
  MA  = CodingAdventures::MosaicAnalyzer
  VM  = CodingAdventures::MosaicVm::MosaicVM
  WCR = CodingAdventures::MosaicEmitWebcomponent::WebComponentRenderer

  # ----------------------------------------------------------------
  # Helper: generate TS from source
  # ----------------------------------------------------------------

  def generate(source)
    ir = MA.analyze(source)
    vm = VM.new(ir)
    result = vm.run(WCR.new)
    result
  end

  def ts(source)
    generate(source)[:files][0][:content]
  end

  # ----------------------------------------------------------------
  # Version
  # ----------------------------------------------------------------

  def test_version_exists
    refute_nil CodingAdventures::MosaicEmitWebcomponent::VERSION
  end

  # ----------------------------------------------------------------
  # Output structure
  # ----------------------------------------------------------------

  def test_emit_returns_files_array
    result = generate("component Label { Text { } }")
    assert_includes result, :files
    assert_equal 1, result[:files].length
  end

  def test_filename_is_kebab_with_mosaic_prefix
    result = generate("component ProfileCard { Text { } }")
    assert_equal "mosaic-profile-card.ts", result[:files][0][:filename]
  end

  def test_simple_component_filename
    result = generate("component Label { Text { } }")
    assert_equal "mosaic-label.ts", result[:files][0][:filename]
  end

  def test_file_content_is_string
    content = ts("component Label { Text { } }")
    assert_kind_of String, content
  end

  # ----------------------------------------------------------------
  # File header
  # ----------------------------------------------------------------

  def test_autogenerated_header
    content = ts("component Label { Text { } }")
    assert_includes content, "AUTO-GENERATED"
  end

  def test_extends_html_element
    content = ts("component Label { Text { } }")
    assert_includes content, "extends HTMLElement"
  end

  def test_shadow_root_field
    content = ts("component Label { Text { } }")
    assert_includes content, "_shadow: ShadowRoot"
  end

  def test_attach_shadow_in_constructor
    content = ts("component Label { Text { } }")
    assert_includes content, "attachShadow"
  end

  def test_connected_callback
    content = ts("component Label { Text { } }")
    assert_includes content, "connectedCallback"
  end

  def test_customelements_define
    content = ts("component ProfileCard { Text { } }")
    assert_includes content, "customElements.define"
    assert_includes content, "mosaic-profile-card"
    assert_includes content, "ProfileCard"
  end

  # ----------------------------------------------------------------
  # Slot → private field + getter/setter
  # ----------------------------------------------------------------

  def test_slot_creates_private_field
    content = ts("component C { slot title: text; Text { } }")
    assert_includes content, "private _title"
  end

  def test_text_slot_type_is_string
    content = ts("component C { slot title: text; Text { } }")
    assert_includes content, "_title: string"
  end

  def test_number_slot_type
    content = ts("component C { slot count: number; Text { } }")
    assert_includes content, "_count: number"
  end

  def test_bool_slot_type
    content = ts("component C { slot visible: bool; Text { } }")
    assert_includes content, "_visible: boolean"
  end

  def test_list_slot_type
    content = ts("component C { slot items: list<text>; Text { } }")
    assert_includes content, "_items: string[]"
  end

  def test_slot_getter_generated
    content = ts("component C { slot title: text; Text { } }")
    assert_includes content, "get title()"
  end

  def test_slot_setter_generated
    content = ts("component C { slot title: text; Text { } }")
    assert_includes content, "set title("
  end

  def test_setter_calls_render
    content = ts("component C { slot title: text; Text { } }")
    assert_includes content, "this._render()"
  end

  # ----------------------------------------------------------------
  # Observed attributes
  # ----------------------------------------------------------------

  def test_scalar_slots_generate_observed_attributes
    content = ts("component C { slot title: text; Text { } }")
    assert_includes content, "observedAttributes"
    assert_includes content, '"title"'
  end

  # ----------------------------------------------------------------
  # _render method
  # ----------------------------------------------------------------

  def test_render_method_present
    content = ts("component Label { Text { } }")
    assert_includes content, "private _render()"
  end

  def test_render_sets_shadow_inner_html
    content = ts("component Label { Text { } }")
    assert_includes content, "this._shadow.innerHTML"
  end

  # ----------------------------------------------------------------
  # HTML tag mapping
  # ----------------------------------------------------------------

  def test_column_maps_to_div
    content = ts("component C { Column { } }")
    assert_includes content, "<div"
  end

  def test_text_maps_to_span
    content = ts("component C { Text { } }")
    assert_includes content, "<span"
  end

  def test_image_maps_to_img
    content = ts("component C { Image { } }")
    assert_includes content, "<img"
  end

  # ----------------------------------------------------------------
  # Content property
  # ----------------------------------------------------------------

  def test_content_literal_text
    content = ts('component C { Text { content: "hello"; } }')
    assert_includes content, "hello"
  end

  def test_content_slot_ref_uses_escape_html
    content = ts("component C { slot label: text; Text { content: @label; } }")
    assert_includes content, "_escapeHtml"
  end

  # ----------------------------------------------------------------
  # Color rendering
  # ----------------------------------------------------------------

  def test_color_rendered_as_rgba
    content = ts("component C { Column { background: #2563eb; } }")
    assert_includes content, "rgba("
    assert_includes content, "background"
  end

  # ----------------------------------------------------------------
  # Dimension rendering
  # ----------------------------------------------------------------

  def test_dimension_dp_to_px
    content = ts("component C { Column { padding: 16dp; } }")
    assert_includes content, "16px"
    assert_includes content, "padding"
  end

  # ----------------------------------------------------------------
  # Security helpers
  # ----------------------------------------------------------------

  def test_escape_html_helper_present
    content = ts("component C { Text { } }")
    assert_includes content, "_escapeHtml"
    assert_includes content, "&amp;"
  end

  def test_validate_url_helper_present
    content = ts("component C { Text { } }")
    assert_includes content, "_validateUrl"
    assert_includes content, "javascript:"
  end

  # ----------------------------------------------------------------
  # when blocks
  # ----------------------------------------------------------------

  def test_when_block_generates_conditional
    source = <<~MOSAIC
      component C {
        slot show: bool;
        Column { when @show { Text { } } }
      }
    MOSAIC
    content = ts(source)
    assert_includes content, "if (this."
  end

  # ----------------------------------------------------------------
  # each blocks
  # ----------------------------------------------------------------

  def test_each_block_generates_foreach
    source = <<~MOSAIC
      component List {
        slot items: list<text>;
        Column { each @items as item { Text { } } }
      }
    MOSAIC
    content = ts(source)
    assert_includes content, "forEach("
    assert_includes content, "item"
  end

  # ----------------------------------------------------------------
  # Slot projection
  # ----------------------------------------------------------------

  def test_slot_projection_generates_slot_element
    source = <<~MOSAIC
      component C {
        slot action: node;
        Column { @action; }
      }
    MOSAIC
    content = ts(source)
    assert_includes content, "<slot"
  end
end
